function switchTCTab(panelId) {
  dom.select_all('.tc-tab').forEach(t => {
    t.classList.toggle('active', t.getAttribute('data-panel') === panelId)
  })
  dom.select_all('.tc-panel').forEach(p => {
    p.classList.toggle('active', p.id === panelId)
  })
}


